                style(&ai.agent_id).cyan().bold(),
                style(format!("({})", ai.model_name)).dim(),
                if ai.usage.is_some() {
                    style("󱐋").yellow()
                } else {
                    style("")
                }
            );

            if !ai.prompt.is_empty() {
                println!(
                    "{:<10} {}",
                    style("Prompt:").dim(),
                    style(format!("\"{}\"", ai.prompt)).italic()
                );
            }

            if let Some(usage) = ai.usage {
                println!(
                    "{:<10} {} {} {}",
                    style("Usage:").dim(),
                    style(format!("+{} tokens", usage.total_tokens)).green(),
                    style("|").dim(),
